const SKILL = "---\nsource: https://github.com/garrytan/gstack/blob/9e244c0bed0fa0ac1e7473e4ca3e6d73944d5634/unfreeze/SKILL.md\ncommit: 9e244c0bed0fa0ac1e7473e4ca3e6d73944d5634\nlicense: MIT (garrytan/gstack)\nrole: optional\nstage: optional\nis_core: false\nported_at: 2026-04-24\nported_by: shogo-template:virtual-engineering-team\nnote: Body below is byte-identical to upstream. Do not edit. Re-run port-gstack.ts to refresh.\n---\n---\nname: unfreeze\nversion: 0.1.0\ndescription: |\n  Clear the freeze boundary set by /freeze, allowing edits to all directories\n  again. Use when you want to widen edit scope without ending the session.\n  Use when asked to \"unfreeze\", \"unlock edits\", \"remove freeze\", or\n  \"allow all edits\". (gstack)\ntriggers:\n  - unfreeze edits\n  - unlock all directories\n  - remove edit restrictions\nallowed-tools:\n  - Bash\n  - Read\n---\n<!-- AUTO-GENERATED from SKILL.md.tmpl — do not edit directly -->\n<!-- Regenerate: bun run gen:skill-docs -->\n\n# /unfreeze — Clear Freeze Boundary\n\nRemove the edit restriction set by `/freeze`, allowing edits to all directories.\n\n```bash\nmkdir -p ~/.gstack/analytics\necho '{\"skill\":\"unfreeze\",\"ts\":\"'$(date -u +%Y-%m-%dT%H:%M:%SZ)'\",\"repo\":\"'$(basename \"$(git rev-parse --show-toplevel 2>/dev/null)\" 2>/dev/null || echo \"unknown\")'\"}'  >> ~/.gstack/analytics/skill-usage.jsonl 2>/dev/null || true\n```\n\n## Clear the boundary\n\n```bash\nSTATE_DIR=\"${CLAUDE_PLUGIN_DATA:-$HOME/.gstack}\"\nif [ -f \"$STATE_DIR/freeze-dir.txt\" ]; then\n  PREV=$(cat \"$STATE_DIR/freeze-dir.txt\")\n  rm -f \"$STATE_DIR/freeze-dir.txt\"\n  echo \"Freeze boundary cleared (was: $PREV). Edits are now allowed everywhere.\"\nelse\n  echo \"No freeze boundary was set.\"\nfi\n```\n\nTell the user the result. Note that `/freeze` hooks are still registered for the\nsession — they will just allow everything since no state file exists. To re-freeze,\nrun `/freeze` again.\n";

export { SKILL as default };
